def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_indices(nums, left, right):
    if left < 0 or right < 0 or left >= len(nums) or right >= len(nums):
        return False
    return True

def solve_with_checks(nums, target):
    left, right = solve(nums, target)
    if left == -1 and right == -1:
        return "No solution"
    if not check_indices(nums, left, right):
        return "Invalid indices"
    return left, right
